-- ============================================================
-- LeadManager SQL Backup  (MySQL 8+ / MariaDB 10.6+ compatible)
-- Generated: $(date)
-- ============================================================
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE IF NOT EXISTS `leads` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `name` VARCHAR(512) NOT NULL,
  `category` VARCHAR(512) NULL,
  `search_category` VARCHAR(512) NULL,
  `address` VARCHAR(1024) NULL,
  `phone` VARCHAR(128) NULL,
  `website` VARCHAR(512) NULL,
  `rating` VARCHAR(16) NULL,
  `review_count` VARCHAR(32) NULL,
  `city` VARCHAR(128) NULL,
  `country` VARCHAR(128) NULL,
  `maps_url` TEXT NULL,
  `scraped_at` VARCHAR(64) NULL,
  `domain` VARCHAR(64) NOT NULL,
  `status` VARCHAR(32) NOT NULL DEFAULT 'NEW',
  `created_at` DATETIME NULL,
  `updated_at` DATETIME NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `notes` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `lead_id` INT UNSIGNED NOT NULL,
  `content` TEXT NOT NULL,
  `created_at` DATETIME NULL,
  FOREIGN KEY (`lead_id`) REFERENCES `leads`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `email_templates` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `name` VARCHAR(256) NOT NULL,
  `language` VARCHAR(8) NOT NULL DEFAULT 'en',
  `domain` VARCHAR(64) NULL,
  `subject` VARCHAR(512) NOT NULL,
  `body` LONGTEXT NOT NULL,
  `created_at` DATETIME NULL,
  `updated_at` DATETIME NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `email_logs` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `lead_id` INT UNSIGNED NOT NULL,
  `template_id` INT UNSIGNED NULL,
  `sent_at` DATETIME NULL,
  `subject` VARCHAR(512) NOT NULL,
  `body` LONGTEXT NOT NULL,
  `status` VARCHAR(32) NOT NULL DEFAULT 'SENT',
  `notes` TEXT NULL,
  FOREIGN KEY (`lead_id`) REFERENCES `leads`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`template_id`) REFERENCES `email_templates`(`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `warmup_plans` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `start_date` DATETIME NOT NULL,
  `total_days` INT NOT NULL DEFAULT 30,
  `created_at` DATETIME NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `warmup_batches` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `plan_id` INT UNSIGNED NOT NULL,
  `day_number` INT NOT NULL,
  `date` DATETIME NOT NULL,
  `quota` INT NOT NULL,
  FOREIGN KEY (`plan_id`) REFERENCES `warmup_plans`(`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS `warmup_batch_leads` (
  `id` INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  `batch_id` INT UNSIGNED NOT NULL,
  `lead_id` INT UNSIGNED NOT NULL,
  `status` VARCHAR(32) NOT NULL DEFAULT 'PENDING',
  `sent_at` DATETIME NULL,
  UNIQUE KEY `ux_batch_lead` (`batch_id`, `lead_id`),
  FOREIGN KEY (`batch_id`) REFERENCES `warmup_batches`(`id`) ON DELETE CASCADE,
  FOREIGN KEY (`lead_id`) REFERENCES `leads`(`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

